// Extract Claude's response text and parse as JSON
const claudeResponse = $input.item.json;
const responseText = claudeResponse.content[0].text;

try {
  // Strip markdown fences if Claude wrapped them
  const cleaned = responseText
    .replace(/```json\n?/g, '')
    .replace(/```\n?/g, '')
    .trim();

  const parsed = JSON.parse(cleaned);
  return { json: parsed };
} catch (err) {
  // If JSON parse fails, return error flag
  return {
    json: {
      is_ticket: false,
      reason: 'Claude response was not valid JSON: ' + err.message,
      raw_response: responseText
    }
  };
}

// Map Claude severity to Jira priority
const item = $input.item.json;

const severityToJiraPriority = {
  'Critical': 'Highest',
  'High': 'High',
  'Medium': 'Medium',
  'Low': 'Low'
};

const severityToColor = {
  'Critical': '#E24B4A',
  'High': '#EF9F27',
  'Medium': '#378ADD',
  'Low': '#888780'
};

// Get the Slack message permalink for traceability
const channelId = $('Slack Trigger').item.json.channel;
const messageTs = $('Slack Trigger').item.json.ts;
const slackLink = `https://slack.com/archives/${channelId}/p${messageTs.replace('.', '')}`;

return {
  json: {
    ...item,
    jira_priority: severityToJiraPriority[item.severity] || 'Medium',
    priority_color: severityToColor[item.severity] || '#888780',
    slack_permalink: slackLink,
    channel_id: channelId,
    thread_ts: messageTs
  }
};

// Build the Slack Block Kit confirmation reply
const parsed = $('Map Priority + Build Metadata').item.json;
const jiraKey = $input.item.json.key;
const jiraDomain = 'https://YOUR_DOMAIN.atlassian.net/'; // REPLACE THIS
const jiraUrl = `https://${jiraDomain}/browse/${jiraKey}`;

const blocks = [
  {
    type: 'section',
    text: {
      type: 'mrkdwn',
      text: ':white_check_mark: *Ticket created*'
    }
  },
  {
    type: 'section',
    fields: [
      { type: 'mrkdwn', text: `*Ticket:*\n<${jiraUrl}|${jiraKey}>` },
      { type: 'mrkdwn', text: `*Priority:*\n${parsed.severity}` },
      { type: 'mrkdwn', text: `*System:*\n${parsed.affected_system}` },
      { type: 'mrkdwn', text: `*Environment:*\n${parsed.environment}` },
      { type: 'mrkdwn', text: `*Category:*\n${parsed.symptom_category}` },
      { type: 'mrkdwn', text: `*Reporter:*\n${parsed.reporter}` }
    ]
  },
  {
    type: 'section',
    text: {
      type: 'mrkdwn',
      text: `*Summary:* ${parsed.summary}`
    }
  },
  {
    type: 'context',
    elements: [
      { type: 'mrkdwn', text: 'Something wrong? React with :x: to flag for review.' }
    ]
  }
];

return {
  json: {
    channel: parsed.channel_id,
    thread_ts: parsed.thread_ts,
    blocks: JSON.stringify(blocks),
    color: parsed.priority_color,
    text: `Ticket ${jiraKey} created: ${parsed.summary}`
  }
};
